 * Atomique : __atomic_sub_fetch pour décrémenter
 * On décrémente un compteur partagé de manière atomique.
 * ========================================================= */
int shared_val = 1000;

void *decrement_example(void *arg) {
    (void)arg;
    for (int i = 0; i < 500; i++) {
        __atomic_sub_fetch(&shared_val, 1, __ATOMIC_SEQ_CST);
    }
    return NULL;
}

void example_atomic_sub(void) {
    pthread_t ta, tb;
    pthread_create(&ta, NULL, decrement_example, NULL);
    pthread_create(&tb, NULL, decrement_example, NULL);
    pthread_join(ta, NULL);
    pthread_join(tb, NULL);
    printf("shared_val: %d (attendu: 0)\n", shared_val);
